use rusqlite::params;

use crate::types::{AgentInfo, IpcError, IpcResult};
use convergio_db::pool::ConnPool;

pub fn register(
    pool: &ConnPool,
    name: &str,
    agent_type: &str,
    pid: Option<u32>,
    host: &str,
    metadata: Option<&str>,
    parent_agent: Option<&str>,
) -> IpcResult<()> {
    let conn = pool.get()?;
    conn.execute(
        "INSERT INTO ipc_agents (name, host, agent_type, pid, metadata, parent_agent,
            registered_at, last_seen)
         VALUES (?1, ?2, ?3, ?4, ?5, ?6,
            strftime('%Y-%m-%dT%H:%M:%f','now'), strftime('%Y-%m-%dT%H:%M:%f','now'))
         ON CONFLICT(name, host) DO UPDATE SET
           agent_type = excluded.agent_type, pid = excluded.pid,
           metadata = excluded.metadata, parent_agent = excluded.parent_agent,
           last_seen = strftime('%Y-%m-%dT%H:%M:%f','now')",
        params![name, host, agent_type, pid, metadata, parent_agent],
    )?;
    tracing::info!(agent = name, host, "agent registered");
    Ok(())
}

pub fn unregister(pool: &ConnPool, name: &str, host: &str) -> IpcResult<()> {
    let conn = pool.get()?;
    let deleted = conn.execute(
        "DELETE FROM ipc_agents WHERE name = ?1 AND host = ?2",
        params![name, host],
    )?;
    if deleted == 0 {
        return Err(IpcError::NotFound(format!("{name}@{host}")));
    }
    tracing::info!(agent = name, host, "agent unregistered");
    Ok(())
}

pub fn list(pool: &ConnPool) -> IpcResult<Vec<AgentInfo>> {
    let conn = pool.get()?;
    let mut stmt = conn.prepare(
        "SELECT name, host, agent_type, pid, last_seen, parent_agent
         FROM ipc_agents ORDER BY name, host",
    )?;
    let agents = stmt
        .query_map([], |row| {
            Ok(AgentInfo {
                name: row.get(0)?,
                host: row.get(1)?,
                agent_type: row.get(2)?,
                pid: row.get(3)?,
                last_seen: row.get(4)?,
                parent_agent: row.get(5)?,
            })
        })?
        .filter_map(|r| r.ok())
        .collect();
    Ok(agents)
}

pub fn heartbeat(pool: &ConnPool, name: &str, host: &str) -> IpcResult<()> {
    let conn = pool.get()?;
    let updated = conn.execute(
        "UPDATE ipc_agents SET last_seen = strftime('%Y-%m-%dT%H:%M:%f','now')
         WHERE name = ?1 AND host = ?2",
        params![name, host],
    )?;
    if updated == 0 {
        return Err(IpcError::NotFound(format!("{name}@{host}")));
    }
    Ok(())
}

pub fn prune_stale(pool: &ConnPool, ttl_secs: u64) -> IpcResult<usize> {
    let conn = pool.get()?;
    let pruned = conn.execute(
        "DELETE FROM ipc_agents WHERE last_seen < strftime('%Y-%m-%dT%H:%M:%f',
         'now', printf('-%d seconds', ?1))",
        params![ttl_secs],
    )?;
    if pruned > 0 {
        tracing::info!(count = pruned, "pruned stale agents");
    }
    Ok(pruned)
}

pub fn prune_dead_pids(pool: &ConnPool, local_host: &str) -> IpcResult<usize> {
    let conn = pool.get()?;
    let mut stmt = conn.prepare("SELECT name, host, pid FROM ipc_agents WHERE pid IS NOT NULL")?;
    let agents: Vec<(String, String, u32)> = stmt
        .query_map([], |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?)))?
        .filter_map(|r| r.ok())
        .collect();

    let mut pruned = 0usize;
    for (name, host, pid) in &agents {
        if host != local_host {
            continue;
        }
        if !is_pid_alive(*pid) {
            conn.execute(
                "DELETE FROM ipc_agents WHERE name = ?1 AND host = ?2",
                params![name, host],
            )?;
            pruned += 1;
        }
    }
    if pruned > 0 {
        tracing::info!(count = pruned, "pruned dead-PID agents");
    }
    Ok(pruned)
}

fn is_pid_alive(pid: u32) -> bool {
    #[cfg(unix)]
    {
        unsafe { libc::kill(pid as i32, 0) == 0 }
    }
    #[cfg(not(unix))]
    {
        let _ = pid;
        true
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn pool() -> ConnPool {
        let p = convergio_db::pool::create_memory_pool().unwrap();
        let conn = p.get().unwrap();
        convergio_db::migration::ensure_registry(&conn).unwrap();
        convergio_db::migration::apply_migrations(&conn, "ipc", &crate::schema::migrations())
            .unwrap();
        p
    }

    #[test]
    fn register_and_list() {
        let p = pool();
        register(&p, "elena", "claude", Some(42), "m5max", None, None).unwrap();
        let agents = list(&p).unwrap();
        assert_eq!(agents.len(), 1);
        assert_eq!(agents[0].name, "elena");
    }

    #[test]
    fn unregister_not_found() {
        let p = pool();
        let err = unregister(&p, "ghost", "nowhere");
        assert!(matches!(err, Err(IpcError::NotFound(_))));
    }

    #[test]
    fn heartbeat_updates_last_seen() {
        let p = pool();
        register(&p, "baccio", "claude", None, "m1pro", None, None).unwrap();
        heartbeat(&p, "baccio", "m1pro").unwrap();
        let agents = list(&p).unwrap();
        assert_eq!(agents.len(), 1);
    }

    #[test]
    fn prune_stale_removes_old() {
        let p = pool();
        register(&p, "old", "claude", None, "h1", None, None).unwrap();
        {
            let conn = p.get().unwrap();
            conn.execute(
                "UPDATE ipc_agents SET last_seen = '2020-01-01T00:00:00.000'
                 WHERE name = 'old'",
                [],
            )
            .unwrap();
        }
        let pruned = prune_stale(&p, 60).unwrap();
        assert_eq!(pruned, 1);
    }
}

use rusqlite::params;

use crate::types::{AlertLevel, BudgetAlert, BudgetEntry, BudgetStatus, IpcResult};
use convergio_db::pool::ConnPool;

// ── Usage tracking ───────────────────────────────

pub fn log_usage(pool: &ConnPool, entry: &BudgetEntry) -> IpcResult<()> {
    let conn = pool.get()?;
    conn.execute(
        "INSERT INTO ipc_budget_log
         (subscription, date, tokens_in, tokens_out, estimated_cost_usd, model, task_ref)
         VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)",
        params![
            entry.subscription,
            entry.date,
            entry.tokens_in,
            entry.tokens_out,
            entry.estimated_cost_usd,
            entry.model,
            entry.task_ref,
        ],
    )?;
    Ok(())
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct DailySummary {
    pub date: String,
    pub total_tokens_in: i64,
    pub total_tokens_out: i64,
    pub total_cost: f64,
}

pub fn get_daily_summary(pool: &ConnPool, subscription: &str) -> IpcResult<Vec<DailySummary>> {
    let conn = pool.get()?;
    let mut stmt = conn.prepare(
        "SELECT date, SUM(tokens_in), SUM(tokens_out), SUM(estimated_cost_usd)
         FROM ipc_budget_log WHERE subscription = ?1
         GROUP BY date ORDER BY date DESC LIMIT 30",
    )?;
    let rows = stmt
        .query_map(params![subscription], |row| {
            Ok(DailySummary {
                date: row.get(0)?,
                total_tokens_in: row.get(1)?,
                total_tokens_out: row.get(2)?,
                total_cost: row.get(3)?,
            })
        })?
        .filter_map(|r| r.ok())
        .collect();
    Ok(rows)
}

// ── Budget status ────────────────────────────────

pub fn get_budget_status(pool: &ConnPool, subscription: &str) -> IpcResult<Option<BudgetStatus>> {
    let conn = pool.get()?;
    let sub_row = conn.query_row(
        "SELECT budget_usd, reset_day FROM ipc_subscriptions WHERE name = ?1",
        params![subscription],
        |row| Ok((row.get::<_, f64>(0)?, row.get::<_, i32>(1)?)),
    );
    let (budget_usd, reset_day) = match sub_row {
        Ok(r) => r,
        Err(rusqlite::Error::QueryReturnedNoRows) => return Ok(None),
        Err(e) => return Err(e.into()),
    };
    let total_spent: f64 = conn
        .query_row(
            "SELECT COALESCE(SUM(estimated_cost_usd), 0.0)
             FROM ipc_budget_log WHERE subscription = ?1",
            params![subscription],
            |r| r.get(0),
        )
        .unwrap_or(0.0);
    let day_count: i64 = conn
        .query_row(
            "SELECT COUNT(DISTINCT date) FROM ipc_budget_log WHERE subscription = ?1",
            params![subscription],
            |r| r.get(0),
        )
        .unwrap_or(1);
    let daily_avg = if day_count > 0 {
        total_spent / day_count as f64
    } else {
        0.0
    };
    let days_remaining = (reset_day - 1).max(1);
    Ok(Some(BudgetStatus {
        subscription: subscription.to_string(),
        budget_usd,
        total_spent,
        remaining_budget: budget_usd - total_spent,
        days_remaining,
        daily_avg,
        projected_total: total_spent + daily_avg * days_remaining as f64,
        usage_pct: if budget_usd > 0.0 {
            (total_spent / budget_usd) * 100.0
        } else {
            0.0
        },
    }))
}

// ── Cost estimation ──────────────────────────────

pub fn estimate_cost(model: &str, tokens_in: i64, tokens_out: i64) -> f64 {
    let (in_rate, out_rate) = match model {
        m if m.contains("opus") => (0.015, 0.075),
        m if m.contains("sonnet") => (0.003, 0.015),
        m if m.contains("haiku") => (0.00025, 0.00125),
        m if m.contains("gpt-4o-mini") => (0.00015, 0.0006),
        m if m.contains("gpt-4o") => (0.005, 0.015),
        _ => (0.003, 0.015),
    };
    (tokens_in as f64 / 1000.0) * in_rate + (tokens_out as f64 / 1000.0) * out_rate
}

// ── Alerts ───────────────────────────────────────

pub fn check_budget_thresholds(
    pool: &ConnPool,
    subscription: &str,
) -> IpcResult<Option<BudgetAlert>> {
    let status = match get_budget_status(pool, subscription)? {
        Some(s) => s,
        None => return Ok(None),
    };
    let pct = status.usage_pct;
    let (level, prefix) = if pct >= 95.0 {
        (AlertLevel::Critical, "CRITICAL")
    } else if pct >= 85.0 {
        (AlertLevel::High, "HIGH")
    } else if pct >= 70.0 {
        (AlertLevel::Warning, "WARNING")
    } else {
        return Ok(None);
    };
    Ok(Some(BudgetAlert {
        subscription: subscription.to_string(),
        level,
        usage_pct: pct,
        message: format!("{prefix}: {subscription} at {pct:.0}%"),
    }))
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::types::BudgetEntry;

    fn pool() -> ConnPool {
        let p = convergio_db::pool::create_memory_pool().unwrap();
        let conn = p.get().unwrap();
        convergio_db::migration::ensure_registry(&conn).unwrap();
        convergio_db::migration::apply_migrations(&conn, "ipc", &crate::schema::migrations())
            .unwrap();
        p
    }

    fn entry(sub: &str, cost: f64) -> BudgetEntry {
        BudgetEntry {
            subscription: sub.into(),
            date: "2026-04-03".into(),
            tokens_in: 100,
            tokens_out: 100,
            estimated_cost_usd: cost,
            model: "claude-sonnet".into(),
            task_ref: "".into(),
        }
    }

    fn add_subscription(pool: &ConnPool, name: &str, budget: f64) {
        let conn = pool.get().unwrap();
        conn.execute(
            "INSERT INTO ipc_subscriptions VALUES (?1, 'anthropic', 'pro', ?2, 30, '[]')",
            params![name, budget],
        )
        .unwrap();
    }

    #[test]
    fn log_and_summary() {
        let p = pool();
        add_subscription(&p, "s1", 100.0);
        log_usage(&p, &entry("s1", 5.0)).unwrap();
        let summary = get_daily_summary(&p, "s1").unwrap();
        assert_eq!(summary.len(), 1);
        assert!((summary[0].total_cost - 5.0).abs() < 0.001);
    }

    #[test]
    fn alert_at_96_pct() {
        let p = pool();
        add_subscription(&p, "s1", 100.0);
        log_usage(&p, &entry("s1", 96.0)).unwrap();
        let alert = check_budget_thresholds(&p, "s1").unwrap().unwrap();
        assert_eq!(alert.level, AlertLevel::Critical);
    }

    #[test]
    fn no_alert_under_70_pct() {
        let p = pool();
        add_subscription(&p, "s1", 100.0);
        log_usage(&p, &entry("s1", 50.0)).unwrap();
        let alert = check_budget_thresholds(&p, "s1").unwrap();
        assert!(alert.is_none());
    }

    #[test]
    fn cost_estimation() {
        let cost = estimate_cost("claude-opus", 1000, 1000);
        assert!((cost - 0.090).abs() < 0.001);
    }
}

use rusqlite::params;

use crate::types::{ChannelInfo, ContextEntry, IpcError, IpcResult};
use convergio_db::pool::ConnPool;

// ── Channels ─────────────────────────────────────

pub fn create_channel(
    pool: &ConnPool,
    name: &str,
    description: Option<&str>,
    created_by: &str,
) -> IpcResult<()> {
    let conn = pool.get()?;
    conn.execute(
        "INSERT OR IGNORE INTO ipc_channels (name, description, created_by)
         VALUES (?1, ?2, ?3)",
        params![name, description, created_by],
    )?;
    Ok(())
}

pub fn list_channels(pool: &ConnPool) -> IpcResult<Vec<ChannelInfo>> {
    let conn = pool.get()?;
    let mut stmt = conn.prepare(
        "SELECT name, description, created_by, created_at
         FROM ipc_channels ORDER BY name",
    )?;
    let channels = stmt
        .query_map([], |row| {
            Ok(ChannelInfo {
                name: row.get(0)?,
                description: row.get(1)?,
                created_by: row.get(2)?,
                created_at: row.get(3)?,
            })
        })?
        .filter_map(|r| r.ok())
        .collect();
    Ok(channels)
}

// ── Shared Context (LWW register) ────────────────

pub fn context_get(pool: &ConnPool, key: &str) -> IpcResult<ContextEntry> {
    let conn = pool.get()?;
    conn.query_row(
        "SELECT key, value, version, set_by, updated_at
         FROM ipc_shared_context WHERE key = ?1",
        params![key],
        |row| {
            Ok(ContextEntry {
                key: row.get(0)?,
                value: row.get(1)?,
                version: row.get(2)?,
                set_by: row.get(3)?,
                updated_at: row.get(4)?,
            })
        },
    )
    .map_err(|e| match e {
        rusqlite::Error::QueryReturnedNoRows => IpcError::NotFound(format!("key '{key}'")),
        other => IpcError::Db(other),
    })
}

pub fn context_set(pool: &ConnPool, key: &str, value: &str, set_by: &str) -> IpcResult<()> {
    let conn = pool.get()?;
    conn.execute(
        "INSERT INTO ipc_shared_context (key, value, version, set_by, updated_at)
         VALUES (?1, ?2, 1, ?3, strftime('%Y-%m-%dT%H:%M:%f','now'))
         ON CONFLICT(key) DO UPDATE SET
           value = excluded.value,
           version = ipc_shared_context.version + 1,
           set_by = excluded.set_by,
           updated_at = strftime('%Y-%m-%dT%H:%M:%f','now')",
        params![key, value, set_by],
    )?;
    Ok(())
}

pub fn context_list(pool: &ConnPool) -> IpcResult<Vec<ContextEntry>> {
    let conn = pool.get()?;
    let mut stmt = conn.prepare(
        "SELECT key, value, version, set_by, updated_at
         FROM ipc_shared_context ORDER BY key",
    )?;
    let entries = stmt
        .query_map([], |row| {
            Ok(ContextEntry {
                key: row.get(0)?,
                value: row.get(1)?,
                version: row.get(2)?,
                set_by: row.get(3)?,
                updated_at: row.get(4)?,
            })
        })?
        .filter_map(|r| r.ok())
        .collect();
    Ok(entries)
}

pub fn context_delete(pool: &ConnPool, key: &str) -> IpcResult<()> {
    let conn = pool.get()?;
    let deleted = conn.execute(
        "DELETE FROM ipc_shared_context WHERE key = ?1",
        params![key],
    )?;
    if deleted == 0 {
        return Err(IpcError::NotFound(format!("key '{key}'")));
    }
    Ok(())
}

// ── DB Maintenance ───────────────────────────────

pub fn cleanup_old_messages(pool: &ConnPool, older_than_days: u32) -> IpcResult<usize> {
    let conn = pool.get()?;
    let deleted = conn.execute(
        "DELETE FROM ipc_messages
         WHERE created_at < datetime('now', '-' || ?1 || ' days')",
        params![older_than_days],
    )?;
    Ok(deleted)
}

pub fn vacuum(pool: &ConnPool) -> IpcResult<()> {
    let conn = pool.get()?;
    conn.execute_batch("PRAGMA wal_checkpoint(TRUNCATE); VACUUM;")?;
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    fn pool() -> ConnPool {
        let p = convergio_db::pool::create_memory_pool().unwrap();
        let conn = p.get().unwrap();
        convergio_db::migration::ensure_registry(&conn).unwrap();
        convergio_db::migration::apply_migrations(&conn, "ipc", &crate::schema::migrations())
            .unwrap();
        p
    }

    #[test]
    fn channel_crud() {
        let p = pool();
        create_channel(&p, "general", Some("Main channel"), "admin").unwrap();
        let channels = list_channels(&p).unwrap();
        assert_eq!(channels.len(), 1);
        assert_eq!(channels[0].name, "general");
    }

    #[test]
    fn context_set_get_delete() {
        let p = pool();
        context_set(&p, "plan_id", "42", "elena").unwrap();
        let entry = context_get(&p, "plan_id").unwrap();
        assert_eq!(entry.value, "42");
        assert_eq!(entry.version, 1);

        context_set(&p, "plan_id", "43", "baccio").unwrap();
        let entry = context_get(&p, "plan_id").unwrap();
        assert_eq!(entry.value, "43");
        assert_eq!(entry.version, 2);

        context_delete(&p, "plan_id").unwrap();
        assert!(matches!(
            context_get(&p, "plan_id"),
            Err(IpcError::NotFound(_))
        ));
    }

    #[test]
    fn context_list_returns_all() {
        let p = pool();
        context_set(&p, "a", "1", "x").unwrap();
        context_set(&p, "b", "2", "x").unwrap();
        let entries = context_list(&p).unwrap();
        assert_eq!(entries.len(), 2);
    }
}

use std::sync::Arc;

use convergio_db::pool::ConnPool;
use convergio_telemetry::health::{ComponentHealth, HealthCheck};
use convergio_telemetry::metrics::MetricSource;
use convergio_types::extension::{
    AppContext, ExtResult, Extension, Health, McpToolDef, Metric, Migration,
};
use convergio_types::manifest::{Capability, Manifest, ModuleKind};
use tokio::sync::Notify;

use crate::sse::EventBus;
use crate::types::IpcStats;

pub struct IpcExtension {
    pool: ConnPool,
    notify: Arc<Notify>,
    event_bus: Arc<EventBus>,
    rate_limit: u32,
}

impl IpcExtension {
    pub fn new(pool: ConnPool) -> Self {
        Self::with_bus(pool, Arc::new(EventBus::new(1024)))
    }

    /// Create with an externally-provided EventBus (for sharing via AppContext).
    pub fn with_bus(pool: ConnPool, event_bus: Arc<EventBus>) -> Self {
        Self {
            pool,
            notify: Arc::new(Notify::new()),
            event_bus,
            rate_limit: crate::messaging::DEFAULT_RATE_LIMIT,
        }
    }

    pub fn pool(&self) -> &ConnPool {
        &self.pool
    }

    pub fn notify(&self) -> &Arc<Notify> {
        &self.notify
    }

    pub fn event_bus(&self) -> &Arc<EventBus> {
        &self.event_bus
    }

    pub fn rate_limit(&self) -> u32 {
        self.rate_limit
    }

    pub fn set_rate_limit(&mut self, limit: u32) {
        self.rate_limit = limit;
    }

    fn state(&self) -> Arc<crate::routes::IpcState> {
        Arc::new(crate::routes::IpcState {
            pool: self.pool.clone(),
            notify: Arc::clone(&self.notify),
            event_bus: Arc::clone(&self.event_bus),
            rate_limit: self.rate_limit,
        })
    }

    pub fn stats(&self) -> Result<IpcStats, crate::types::IpcError> {
        let conn = self.pool.get()?;
        let agents: u64 = conn.query_row("SELECT count(*) FROM ipc_agents", [], |r| r.get(0))?;
        let messages: u64 =
            conn.query_row("SELECT count(*) FROM ipc_messages", [], |r| r.get(0))?;
        let channels: u64 =
            conn.query_row("SELECT count(*) FROM ipc_channels", [], |r| r.get(0))?;
        let context_keys: u64 =
            conn.query_row("SELECT count(*) FROM ipc_shared_context", [], |r| r.get(0))?;
        Ok(IpcStats {
            agents,
            messages,
            channels,
            context_keys,
        })
    }
}

impl Extension for IpcExtension {
    fn manifest(&self) -> Manifest {
        Manifest {
            id: "convergio-ipc".into(),
            description: "Message bus, SSE streaming, agent registry".into(),
            version: "1.0.0".into(),
            kind: ModuleKind::Core,
            provides: vec![
                Capability {
                    name: "ipc-bus".into(),
                    version: "1.0.0".into(),
                    description: "Agent-to-agent messaging with channels".into(),
                },
                Capability {
                    name: "sse-events".into(),
                    version: "1.0.0".into(),
                    description: "Real-time event streaming via SSE".into(),
                },
                Capability {
                    name: "agent-registry".into(),
                    version: "1.0.0".into(),
                    description: "Agent registration and discovery".into(),
                },
            ],
            requires: vec![],
            agent_tools: vec![],
            required_roles: vec![],
        }
    }

    fn routes(&self, _ctx: &AppContext) -> Option<axum::Router> {
        Some(crate::routes::ipc_routes(self.state()))
    }

    fn migrations(&self) -> Vec<Migration> {
        crate::schema::migrations()
    }

    fn health(&self) -> Health {
        match self.stats() {
            Ok(_) => Health::Ok,
            Err(e) => Health::Degraded {
                reason: format!("IPC stats failed: {e}"),
            },
        }
    }

    fn metrics(&self) -> Vec<Metric> {
        match self.stats() {
            Ok(s) => vec![
                Metric {
                    name: "ipc_agents".into(),
                    value: s.agents as f64,
                    labels: vec![],
                },
                Metric {
                    name: "ipc_messages".into(),
                    value: s.messages as f64,
                    labels: vec![],
                },
                Metric {
                    name: "ipc_channels".into(),
                    value: s.channels as f64,
                    labels: vec![],
                },
            ],
            Err(_) => vec![],
        }
    }

    fn on_start(&self, _ctx: &AppContext) -> ExtResult<()> {
        crate::process_scanner::spawn_process_scanner(self.pool.clone());
        tracing::info!("IPC extension started (process scanner active)");
        Ok(())
    }

    fn on_shutdown(&self) -> ExtResult<()> {
        tracing::info!("IPC extension shutdown");
        Ok(())
    }

    fn mcp_tools(&self) -> Vec<McpToolDef> {
        crate::mcp_defs::ipc_tools()
    }
}

impl HealthCheck for IpcExtension {
    fn name(&self) -> &str {
        "ipc"
    }

    fn check(&self) -> ComponentHealth {
        let (status, message) = match self.stats() {
            Ok(s) => (
                Health::Ok,
                Some(format!("{} agents, {} msgs", s.agents, s.messages)),
            ),
            Err(e) => (
                Health::Degraded {
                    reason: e.to_string(),
                },
                None,
            ),
        };
        ComponentHealth {
            name: "ipc".into(),
            status,
            message,
        }
    }
}

impl MetricSource for IpcExtension {
    fn name(&self) -> &str {
        "ipc"
    }

    fn collect(&self) -> Vec<Metric> {
        self.metrics()
    }
}

