//! Process scanner — discovers external AI agents (Claude Code, Copilot, MLX)
//! by inspecting OS processes and registers them in ipc_agents.

use convergio_db::pool::ConnPool;
use std::time::Duration;

/// Agent type tags for externally discovered processes.
const TYPE_CLAUDE: &str = "external-claude";
const TYPE_COPILOT: &str = "external-copilot";
const TYPE_MLX: &str = "external-mlx";

/// Scan interval: 15 seconds.
const SCAN_INTERVAL: Duration = Duration::from_secs(15);

/// Max agent age before pruning (5 minutes without refresh).
const STALE_TTL_SECS: u64 = 300;

struct FoundAgent {
    name: String,
    agent_type: &'static str,
    pid: u32,
    raw_cmd: String,
    metadata: String,
}

/// Spawn a background task that periodically scans for AI agent processes.
pub fn spawn_process_scanner(pool: ConnPool) {
    tokio::spawn(async move {
        tracing::info!("process scanner started");
        loop {
            tokio::time::sleep(SCAN_INTERVAL).await;
            let p = pool.clone();
            if let Err(e) = tokio::task::spawn_blocking(move || scan_round(&p)).await {
                tracing::error!("process scanner panicked: {e}");
            }
        }
    });
}

fn scan_round(pool: &ConnPool) {
    let host = hostname();
    let agents = discover_agents();
    for agent in &agents {
        let meta = Some(agent.metadata.as_str());
        if let Err(e) = crate::agents::register(
            pool,
            &agent.name,
            agent.agent_type,
            Some(agent.pid),
            &host,
            meta,
            None,
        ) {
            tracing::warn!(name = %agent.name, "scanner register failed: {e}");
        }
    }
    // Prune agents whose PIDs are gone
    let _ = crate::agents::prune_dead_pids(pool, &host);
    // Prune agents not seen for STALE_TTL_SECS
    let _ = crate::agents::prune_stale(pool, STALE_TTL_SECS);
}

fn discover_agents() -> Vec<FoundAgent> {
    let output = match std::process::Command::new("ps").args(["aux"]).output() {
        Ok(o) => String::from_utf8_lossy(&o.stdout).to_string(),
        Err(_) => return vec![],
    };
    let mut agents = Vec::new();
    for line in output.lines() {
        let parts: Vec<&str> = line.split_whitespace().collect();
        if parts.len() < 11 {
            continue;
        }
        let pid: u32 = match parts[1].parse() {
            Ok(p) => p,
            Err(_) => continue,
        };
        let cmd = parts[10..].join(" ");
        if let Some(agent) = classify_process(pid, &cmd) {
            agents.push(agent);
        }
    }
    dedup_by_command(&mut agents);
    agents
}

/// Deduplicate agents with identical commands — keep only the highest PID
/// (the leaf child process). Prevents registering both parent wrapper and
/// child process for the same Copilot/Claude session.
fn dedup_by_command(agents: &mut Vec<FoundAgent>) {
    agents.sort_by(|a, b| {
        a.agent_type
            .cmp(b.agent_type)
            .then(a.raw_cmd.cmp(&b.raw_cmd))
            .then(b.pid.cmp(&a.pid))
    });
    agents.dedup_by(|a, b| a.agent_type == b.agent_type && a.raw_cmd == b.raw_cmd);
}

fn classify_process(pid: u32, cmd: &str) -> Option<FoundAgent> {
    // Skip our own grep/ps processes
    if cmd.contains("grep") || cmd.contains("process_scanner") {
        return None;
    }
    // Claude Code sessions
    if is_claude_process(cmd) {
        let flags = extract_flags(cmd);
        return Some(FoundAgent {
            name: format!("claude-{pid}"),
            agent_type: TYPE_CLAUDE,
            pid,
            raw_cmd: cmd.to_string(),
            metadata: serde_json::json!({"cmd": truncate(cmd, 200), "flags": flags}).to_string(),
        });
    }
    // GitHub Copilot — actual binary only, not `gh` wrapper or unrelated apps
    if is_copilot_process(cmd) {
        return Some(FoundAgent {
            name: format!("copilot-{pid}"),
            agent_type: TYPE_COPILOT,
            pid,
            raw_cmd: cmd.to_string(),
            metadata: serde_json::json!({"cmd": truncate(cmd, 200)}).to_string(),
        });
    }
    // MLX / local model servers
    if cmd.contains("mlx_lm") || cmd.contains("omlx serve") || cmd.contains("mlx-server") {
        let model = extract_model_name(cmd);
        return Some(FoundAgent {
            name: format!("mlx-{pid}"),
            agent_type: TYPE_MLX,
            pid,
            raw_cmd: cmd.to_string(),
            metadata: serde_json::json!({"cmd": truncate(cmd, 200), "model": model}).to_string(),
        });
    }
    None
}

/// Match actual Copilot agent processes, filtering out `gh` CLI wrappers
/// and unrelated apps (Teams, Edge) that contain "copilot" in URLs.
fn is_copilot_process(cmd: &str) -> bool {
    let lower = cmd.to_lowercase();
    if !lower.contains("copilot") {
        return false;
    }
    // `gh copilot ...` is the parent CLI wrapper — skip it
    if lower.starts_with("gh ") {
        return false;
    }
    // Non-AI apps that coincidentally contain "copilot" in command/URLs
    if lower.contains(".app/")
        || lower.contains("microsoft")
        || lower.contains("webview")
        || lower.contains("teams")
    {
        return false;
    }
    // Detached dev servers are not agent sessions
    if lower.contains("copilot-detached-dev-server") {
        return false;
    }
    true
}

fn is_claude_process(cmd: &str) -> bool {
    // Match: `claude` binary or `node ... claude`
    // Exclude: `claude-daemon`, cargo/build references
    let lower = cmd.to_lowercase();
    (lower.starts_with("claude ") || lower.contains("/claude ") || lower.contains("/claude\0"))
        && !lower.contains("cargo")
        && !lower.contains("target/")
}

fn extract_flags(cmd: &str) -> String {
    cmd.split_whitespace()
        .filter(|w| w.starts_with("--"))
        .collect::<Vec<_>>()
        .join(" ")
}

fn extract_model_name(cmd: &str) -> String {
    let parts: Vec<&str> = cmd.split_whitespace().collect();
    for (i, part) in parts.iter().enumerate() {
        if *part == "--model-dir" || *part == "--model" {
            if let Some(path) = parts.get(i + 1) {
                return path.rsplit('/').next().unwrap_or(path).to_string();
            }
        }
    }
    "unknown".to_string()
}

fn truncate(s: &str, max: usize) -> String {
    if s.len() <= max {
        s.to_string()
    } else {
        format!("{}...", &s[..max])
    }
}

fn hostname() -> String {
    let mut buf = [0u8; 256];
    #[cfg(unix)]
    unsafe {
        libc::gethostname(buf.as_mut_ptr() as *mut libc::c_char, buf.len());
    }
    let end = buf.iter().position(|&b| b == 0).unwrap_or(buf.len());
    String::from_utf8_lossy(&buf[..end]).to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn classify_claude() {
        let a = classify_process(1234, "claude --dangerously-skip-permissions");
        assert!(a.is_some());
        let a = a.unwrap();
        assert_eq!(a.agent_type, TYPE_CLAUDE);
        assert_eq!(a.name, "claude-1234");
    }

    #[test]
    fn classify_mlx() {
        let cmd = "/usr/bin/python omlx serve --model-dir /path/to/qwen --port 8321";
        let a = classify_process(5678, cmd).unwrap();
        assert_eq!(a.agent_type, TYPE_MLX);
        assert!(a.metadata.contains("qwen"));
    }

    #[test]
    fn classify_copilot() {
        let a = classify_process(99, "/Users/u/.local/share/gh/copilot/copilot --yolo");
        assert!(a.is_some());
        assert_eq!(a.unwrap().agent_type, TYPE_COPILOT);
    }

    #[test]
    fn classify_copilot_agent_stdio() {
        let a = classify_process(99, "copilot-agent --stdio");
        assert!(a.is_some());
        assert_eq!(a.unwrap().agent_type, TYPE_COPILOT);
    }

    #[test]
    fn classify_ignores_gh_wrapper() {
        assert!(classify_process(99, "gh copilot --yolo").is_none());
    }

    #[test]
    fn classify_ignores_teams_copilot() {
        let teams = "/Applications/Microsoft Teams.app/Contents/MacOS/Teams --copilot.teams.cloud";
        assert!(classify_process(99, teams).is_none());
    }

    #[test]
    fn dedup_keeps_highest_pid() {
        let cmd = "/Users/u/.local/share/gh/copilot/copilot --yolo";
        let mut agents = vec![
            classify_process(100, cmd).unwrap(),
            classify_process(101, cmd).unwrap(),
        ];
        dedup_by_command(&mut agents);
        assert_eq!(agents.len(), 1);
        assert_eq!(agents[0].pid, 101);
    }

    #[test]
    fn classify_ignores_grep() {
        assert!(classify_process(1, "grep claude").is_none());
    }

    #[test]
    fn classify_ignores_cargo() {
        assert!(classify_process(1, "cargo test claude").is_none());
    }

    #[test]
    fn extract_model_from_cmd() {
        let m = extract_model_name("omlx serve --model-dir /models/qwen3.5-27b --port 8321");
        assert_eq!(m, "qwen3.5-27b");
    }
}

//! HTTP API routes for IPC.
//!
//! - GET  /api/ipc/status   — IPC stats (agents, messages, channels)
//! - GET  /api/ipc/agents   — registered agents list
//! - GET  /api/ipc/channels — channel list
//! - GET  /api/ipc/context  — shared context entries
//! - POST /api/ipc/context  — set a shared context key/value
//! - GET  /api/ipc/messages — message history (query: agent, channel, limit)
//! - GET  /api/ipc/stream   — SSE event stream (query: agent filter)
//! - GET  /api/events/stream — SSE event stream (legacy path)
//! - POST /api/ipc/send     — send a direct message

#[path = "routes_handlers.rs"]
mod routes_handlers;

use std::sync::Arc;

use axum::extract::ws::WebSocketUpgrade;
use axum::extract::{Query, State};
use axum::response::sse::{self, Sse};
use axum::response::IntoResponse;
use axum::routing::{get, post};
use axum::Router;
use tokio::sync::Notify;

use convergio_db::pool::ConnPool;

use crate::sse::{create_sse_stream, EventBus};
use crate::websocket;

pub struct IpcState {
    pub pool: ConnPool,
    pub notify: Arc<Notify>,
    pub event_bus: Arc<EventBus>,
    pub rate_limit: u32,
}

pub fn ipc_routes(state: Arc<IpcState>) -> Router {
    let bus = Arc::clone(&state.event_bus);
    Router::new()
        .route("/api/ipc/status", get(routes_handlers::handle_status))
        .route("/api/ipc/agents", get(routes_handlers::handle_agents))
        .route("/api/ipc/channels", get(routes_handlers::handle_channels))
        .route(
            "/api/ipc/context",
            get(routes_handlers::handle_context).post(routes_handlers::handle_context_set),
        )
        .route("/api/ipc/messages", get(routes_handlers::handle_messages))
        .route("/api/ipc/stream", get(routes_handlers::handle_stream))
        .route("/api/ws/agent-chat", get(ws_agent_chat_handler))
        .route("/api/ipc/send", post(routes_handlers::handle_send))
        .route(
            "/api/ipc/agents/register",
            post(routes_handlers::handle_register_agent),
        )
        .route(
            "/api/ipc/agents/heartbeat",
            post(routes_handlers::handle_agent_heartbeat),
        )
        .route(
            "/api/ipc/agents/:name",
            axum::routing::delete(routes_handlers::handle_unregister_agent),
        )
        .with_state(state)
        .merge(event_routes(bus))
}

/// Legacy SSE stream at /api/events/stream (from main branch).
pub fn event_routes(bus: Arc<EventBus>) -> Router {
    Router::new()
        .route("/api/events/stream", get(legacy_stream_handler))
        .with_state(bus)
}

#[derive(serde::Deserialize, Default)]
pub struct LegacyStreamQuery {
    agent_filter: Option<String>,
}

async fn legacy_stream_handler(
    State(bus): State<Arc<EventBus>>,
    Query(q): Query<LegacyStreamQuery>,
) -> Sse<impl futures_core::Stream<Item = Result<sse::Event, std::convert::Infallible>>> {
    Sse::new(create_sse_stream(bus, q.agent_filter)).keep_alive(sse::KeepAlive::default())
}

/// WebSocket upgrade handler for agent chat.
async fn ws_agent_chat_handler(
    State(state): State<Arc<IpcState>>,
    ws: WebSocketUpgrade,
) -> impl IntoResponse {
    let bus = Arc::clone(&state.event_bus);
    ws.on_upgrade(move |socket| websocket::handle_ws(socket, bus))
}

fn local_hostname() -> String {
    let mut buf = [0u8; 256];
    #[cfg(unix)]
    unsafe {
        libc::gethostname(buf.as_mut_ptr() as *mut libc::c_char, buf.len());
    }
    let end = buf.iter().position(|&b| b == 0).unwrap_or(buf.len());
    String::from_utf8_lossy(&buf[..end]).to_string()
}

//! IPC route handlers — agent management, messaging, and status.

use std::sync::Arc;

use axum::extract::{Query, State};
use axum::response::sse::{self, Sse};
use axum::response::Json;
use serde::Deserialize;

use crate::sse::create_sse_stream;

use super::IpcState;

pub async fn handle_status(State(state): State<Arc<IpcState>>) -> Json<serde_json::Value> {
    let conn = match state.pool.get() {
        Ok(c) => c,
        Err(e) => return Json(serde_json::json!({"error": e.to_string()})),
    };
    let agents: u64 = conn
        .query_row("SELECT count(*) FROM ipc_agents", [], |r| r.get(0))
        .unwrap_or(0);
    let messages: u64 = conn
        .query_row("SELECT count(*) FROM ipc_messages", [], |r| r.get(0))
        .unwrap_or(0);
    let channels: u64 = conn
        .query_row("SELECT count(*) FROM ipc_channels", [], |r| r.get(0))
        .unwrap_or(0);
    Json(serde_json::json!({
        "agents": agents,
        "messages": messages,
        "channels": channels,
    }))
}

pub async fn handle_agents(State(state): State<Arc<IpcState>>) -> Json<serde_json::Value> {
    match crate::agents::list(&state.pool) {
        Ok(agents) => Json(serde_json::json!(agents)),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

pub async fn handle_channels(State(state): State<Arc<IpcState>>) -> Json<serde_json::Value> {
    match crate::channels::list_channels(&state.pool) {
        Ok(ch) => Json(serde_json::json!(ch)),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

pub async fn handle_context(State(state): State<Arc<IpcState>>) -> Json<serde_json::Value> {
    match crate::channels::context_list(&state.pool) {
        Ok(ctx) => Json(serde_json::json!(ctx)),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

#[derive(Debug, Deserialize)]
pub struct MessagesQuery {
    pub agent: Option<String>,
    pub channel: Option<String>,
    pub limit: Option<u32>,
}

pub async fn handle_messages(
    State(state): State<Arc<IpcState>>,
    Query(params): Query<MessagesQuery>,
) -> Json<serde_json::Value> {
    let limit = params.limit.unwrap_or(50).min(200);
    match crate::messaging::history(
        &state.pool,
        params.agent.as_deref(),
        params.channel.as_deref(),
        limit,
        None,
    ) {
        Ok(msgs) => Json(serde_json::json!(msgs)),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

#[derive(Debug, Deserialize)]
pub struct StreamQuery {
    pub agent: Option<String>,
}

pub async fn handle_stream(
    State(state): State<Arc<IpcState>>,
    Query(params): Query<StreamQuery>,
) -> Sse<impl futures_core::Stream<Item = Result<sse::Event, std::convert::Infallible>>> {
    Sse::new(create_sse_stream(
        Arc::clone(&state.event_bus),
        params.agent,
    ))
}

#[derive(Debug, Deserialize)]
pub struct SendRequest {
    pub from: String,
    pub to: String,
    pub content: String,
    #[serde(default = "default_msg_type")]
    pub msg_type: String,
    #[serde(default)]
    pub priority: i32,
}

fn default_msg_type() -> String {
    "text".into()
}

pub async fn handle_send(
    State(state): State<Arc<IpcState>>,
    Json(body): Json<SendRequest>,
) -> Json<serde_json::Value> {
    let params = crate::messaging::SendParams {
        from: &body.from,
        to: &body.to,
        content: &body.content,
        msg_type: &body.msg_type,
        priority: body.priority,
        rate_limit: state.rate_limit,
    };
    match crate::messaging::send(&state.pool, &state.notify, &params) {
        Ok(id) => Json(serde_json::json!({"id": id})),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

#[derive(Debug, Deserialize)]
pub struct RegisterAgentRequest {
    pub name: String,
    #[serde(default = "default_agent_type")]
    pub agent_type: String,
    pub pid: Option<u32>,
    pub host: Option<String>,
    pub metadata: Option<String>,
    pub parent_agent: Option<String>,
}

fn default_agent_type() -> String {
    "claude".into()
}

#[derive(Debug, Deserialize)]
pub struct ContextSetRequest {
    pub key: String,
    pub value: String,
    #[serde(default = "default_context_set_by")]
    pub set_by: String,
}

fn default_context_set_by() -> String {
    "api".into()
}

pub async fn handle_context_set(
    State(state): State<Arc<IpcState>>,
    Json(body): Json<ContextSetRequest>,
) -> Json<serde_json::Value> {
    match crate::channels::context_set(&state.pool, &body.key, &body.value, &body.set_by) {
        Ok(()) => Json(serde_json::json!({"ok": true})),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

pub async fn handle_register_agent(
    State(state): State<Arc<IpcState>>,
    Json(body): Json<RegisterAgentRequest>,
) -> Json<serde_json::Value> {
    let host = body.host.unwrap_or_else(super::local_hostname);
    match crate::agents::register(
        &state.pool,
        &body.name,
        &body.agent_type,
        body.pid,
        &host,
        body.metadata.as_deref(),
        body.parent_agent.as_deref(),
    ) {
        Ok(()) => Json(serde_json::json!({"ok": true})),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

pub async fn handle_unregister_agent(
    State(state): State<Arc<IpcState>>,
    axum::extract::Path(name): axum::extract::Path<String>,
) -> Json<serde_json::Value> {
    let host = super::local_hostname();
    match crate::agents::unregister(&state.pool, &name, &host) {
        Ok(()) => Json(serde_json::json!({"ok": true})),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

#[derive(Debug, Deserialize)]
pub struct HeartbeatAgentRequest {
    pub name: String,
    pub host: Option<String>,
}

pub async fn handle_agent_heartbeat(
    State(state): State<Arc<IpcState>>,
    Json(body): Json<HeartbeatAgentRequest>,
) -> Json<serde_json::Value> {
    let host = body.host.unwrap_or_else(super::local_hostname);
    match crate::agents::heartbeat(&state.pool, &body.name, &host) {
        Ok(()) => Json(serde_json::json!({"ok": true})),
        Err(e) => Json(serde_json::json!({"error": e.to_string()})),
    }
}

